import java.util.concurrent.*;
import java.util.concurrent.CompletableFuture;

public class CompletableFutureDemo {

    // Simulated async services (would be HTTP calls in real app)
    static CompletableFuture<String> fetchUser(long userId) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(100); // simulate I/O
            if (userId <= 0) throw new IllegalArgumentException("Invalid userId: " + userId);
            return "User#" + userId;
        });
    }

    static CompletableFuture<String> fetchOrders(String user) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(80);
            return "Orders for " + user + ": [O1, O2, O3]";
        });
    }

    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    public static void main(String[] args) throws Exception {
        System.out.println("=== Sequential async pipeline ===");
        // thenCompose = flat-map: fetchUser, THEN fetchOrders (depends on user)
        String result = fetchUser(42)
            .thenCompose(user -> fetchOrders(user))   // sequential chain
            .thenApply(orders -> orders.toUpperCase()) // transform result
            .exceptionally(ex -> "Error: " + ex.getMessage())
            .join(); // block only at end
        System.out.println(result);

        System.out.println("\n=== Error handling ===");
        String errResult = fetchUser(-1)
            .thenApply(u -> "Hello " + u)
            .exceptionally(ex -> "Fallback: anonymous user") // handles error
            .join();
        System.out.println(errResult);

        System.out.println("\n=== Parallel independent tasks ===");
        long start = System.currentTimeMillis();
        CompletableFuture<String> cf1 = fetchUser(1);
        CompletableFuture<String> cf2 = fetchUser(2);
        CompletableFuture<String> cf3 = fetchUser(3);

        CompletableFuture.allOf(cf1, cf2, cf3).join();
        System.out.printf("3 parallel fetches in %dms (vs ~300ms sequential)%n",
            System.currentTimeMillis() - start);
        System.out.println(cf1.join() + ", " + cf2.join() + ", " + cf3.join());
    }
}

import java.util.concurrent.*;

public class AdvancedCF {

    // Custom thread pool for I/O-bound tasks
    static final ExecutorService IO_POOL = Executors.newFixedThreadPool(10);

    static CompletableFuture<Integer> fetchPrice(String product) {
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(100); } catch (Exception e) {}
            return product.length() * 10; // simulated price
        }, IO_POOL); // use custom pool, not commonPool
    }

    static CompletableFuture<Integer> fetchStock(String product) {
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(80); } catch (Exception e) {}
            return product.length() * 5; // simulated stock
        }, IO_POOL);
    }

    public static void main(String[] args) throws Exception {
        // thenCombine: merge two independent async results
        CompletableFuture<String> productInfo = fetchPrice("Laptop")
            .thenCombine(fetchStock("Laptop"), (price, stock) ->
                String.format("Price: $%d, Stock: %d units", price, stock));
        System.out.println(productInfo.join());
        // Both fetches run SIMULTANEOUSLY

        // handle: deal with both success and error in one place
        CompletableFuture<String> safe = CompletableFuture
            .supplyAsync(() -> { throw new RuntimeException("DB down"); })
            .handle((result, ex) -> {
                if (ex != null) return "Cached: fallback data"; // error path
                return result.toString();                       // success path
            });
        System.out.println(safe.join()); // Cached: fallback data

        // whenComplete: side effect (logging) without changing result
        fetchPrice("Phone")
            .whenComplete((price, ex) -> {
                if (ex != null) System.err.println("Failed: " + ex.getMessage());
                else System.out.println("Fetched price: " + price + " (logged)");
            })
            .thenApply(price -> price * 2) // continue chain with original result
            .join();

        IO_POOL.shutdown();
    }
}

