        return CompletableFuture.supplyAsync(() -> { sleep(200); return "Alice"; });
    }
    static CompletableFuture<String> getEmail(int id) {
        return CompletableFuture.supplyAsync(() -> { sleep(200); return "alice@example.com"; });
    }
    static CompletableFuture<Integer> getAge(int id) {
        return CompletableFuture.supplyAsync(() -> { sleep(200); return 30; });
    }
