    public static void main(String[] args) {
        long start = System.currentTimeMillis();
        var cfName  = getUsername(1);
        var cfEmail = getEmail(1);
        var cfAge   = getAge(1);

        CompletableFuture.allOf(cfName, cfEmail, cfAge).join();

        Map<String,Object> user = new LinkedHashMap<>();
        user.put("name",  cfName.join());
        user.put("email", cfEmail.join());
        user.put("age",   cfAge.join());

        System.out.println(user);
        System.out.println("Time: " + (System.currentTimeMillis() - start) + "ms (~200ms)");
    }
}

