import java.util.concurrent.*;

public class Q2 {
    static CompletableFuture<String> slowFetch(int delayMs) {
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(delayMs); } catch (Exception e) {}
            return "real data";
        });
    }

    public static void main(String[] args) {
        // Fast: 100ms < 150ms timeout → real data
        String fast = slowFetch(100)
            .completeOnTimeout("fallback data", 150, TimeUnit.MILLISECONDS)
            .join();
        System.out.println("Fast: " + fast); // real data

        // Slow: 300ms > 150ms timeout → fallback
        String slow = slowFetch(300)
            .completeOnTimeout("fallback data", 150, TimeUnit.MILLISECONDS)
            .join();
        System.out.println("Slow: " + slow); // fallback data

        // Alternative with exception:
        String withEx = slowFetch(300)
            .orTimeout(150, TimeUnit.MILLISECONDS)
            .exceptionally(ex -> "cached: fallback")
            .join();
        System.out.println("orTimeout: " + withEx);
    }
}

