import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;

public class Q3 {
    static CompletableFuture<String> fetch(String name) {
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(100); } catch (Exception e) {}
            return name + "-data";
        });
    }

    public static void main(String[] args) {
        String[] services = {"UserSvc", "OrderSvc", "ProductSvc", "NotifSvc"};

        // Sequential (~400ms)
        long t1 = System.currentTimeMillis();
        List<String> seq = new ArrayList<>();
        CompletableFuture<Void> chain = CompletableFuture.completedFuture(null);
        for (String s : services) {
            chain = chain.thenCompose(v -> fetch(s).thenAccept(seq::add));
        }
        chain.join();
        System.out.println("Sequential: " + (System.currentTimeMillis()-t1) + "ms → " + seq);

        // Parallel (~100ms)
        long t2 = System.currentTimeMillis();
        List<CompletableFuture<String>> cfs = Arrays.stream(services)
            .map(Q3::fetch).collect(Collectors.toList());
        CompletableFuture.allOf(cfs.toArray(new CompletableFuture[0])).join();
        List<String> par = cfs.stream().map(CompletableFuture::join).collect(Collectors.toList());
        System.out.println("Parallel:   " + (System.currentTimeMillis()-t2) + "ms → " + par);
    }
}
